#![no_std]
//! zkVM C Interface Bindings
//!
//! This crate provides Rust bindings generated by bindgen from the standard zkVM
//! C interface headers.
//!
//! All types, constants, and function declarations are re-exported at the crate root.
#![allow(
    non_camel_case_types,
    non_snake_case,
    non_upper_case_globals,
    dead_code,
    unused_imports,
    clippy::all
)]
include!(concat!(env!("OUT_DIR"), "/zkvm_interface_bindings.rs"));
